/**
 * OpenSpec 框架解析器
 */
import * as vscode from 'vscode';
import {
  ISpecParser,
  SpecFramework,
  FrameworkSpecInfo,
  SpecFileInfo,
  CapabilityInfo,
  ChangeInfo,
} from '../types';
import { printLog } from '../../logHandler/logHandler';
import getErrorMessage from '../../../utils/getErrorMessage';

/**
 * OpenSpec 解析器
 * 解析 openspec/ 目录结构
 */
export class OpenSpecParser implements ISpecParser {
  readonly framework = SpecFramework.OpenSpec;
  readonly rootDirName = 'openspec';

  /**
   * 检测工作区是否存在 openspec 目录
   */
  async detect(workspaceRoot: vscode.Uri): Promise<boolean> {
    try {
      const openspecUri = vscode.Uri.joinPath(workspaceRoot, this.rootDirName);
      const stat = await vscode.workspace.fs.stat(openspecUri);
      return stat.type === vscode.FileType.Directory;
    } catch {
      return false;
    }
  }

  /**
   * 解析 OpenSpec 目录结构
   */
  async parse(workspaceRoot: vscode.Uri): Promise<FrameworkSpecInfo> {
    printLog('[OpenSpecParser] Starting to parse OpenSpec...');

    const openspecUri = vscode.Uri.joinPath(workspaceRoot, this.rootDirName);
    const result: FrameworkSpecInfo = {
      framework: this.framework,
      rootPath: this.rootDirName,
      capabilities: [],
      activeChanges: [],
    };

    try {
      // 检测 OpenSpec 版本
      result.version = await this.detectOpenSpecVersion(openspecUri);
      printLog(`[OpenSpecParser] Detected version: ${result.version}`);

      // 解析 project.md
      result.projectContext = await this.parseProjectContext(openspecUri);

      // 解析 specs/ 目录
      result.capabilities = await this.parseCapabilities(openspecUri);

      // 解析 changes/ 目录 (排除 archive)
      result.activeChanges = await this.parseActiveChanges(openspecUri);

      printLog(
        `[OpenSpecParser] Parse completed - version: ${result.version}, capabilities: ${result.capabilities.length}, changes: ${result.activeChanges.length}`
      );
    } catch (error) {
      printLog(
        `[OpenSpecParser] Parse error: ${getErrorMessage(error)}`
      );
    }

    return result;
  }

  /**
   * 检测 OpenSpec 版本
   * 检测规则：
   * - 存在 AGENTS.md → 0.23
   * - 存在 openspec/ 目录但无 AGENTS.md → 1.x
   * - 都不存在 → 'unknown'
   */
  private async detectOpenSpecVersion(
    openspecUri: vscode.Uri
  ): Promise<'0.23' | '1.x' | 'unknown'> {
    try {
      const agentsMdUri = vscode.Uri.joinPath(openspecUri, 'AGENTS.md');
      const stat = await vscode.workspace.fs.stat(agentsMdUri);
      // AGENTS.md 存在 → 0.23
      if (stat.type === vscode.FileType.File) {
        return '0.23';
      }
    } catch {
      // AGENTS.md 不存在
    }

    // openspec 目录存在但无 AGENTS.md → 1.x
    try {
      const stat = await vscode.workspace.fs.stat(openspecUri);
      if (stat.type === vscode.FileType.Directory) {
        return '1.x';
      }
    } catch {
      // openspec 目录不存在
    }

    return 'unknown';
  }

  /**
   * 解析 project.md 文件
   */
  private async parseProjectContext(
    openspecUri: vscode.Uri
  ): Promise<string | undefined> {
    try {
      const projectMdUri = vscode.Uri.joinPath(openspecUri, 'project.md');
      const content = await vscode.workspace.fs.readFile(projectMdUri);
      return Buffer.from(content).toString('utf8');
    } catch {
      printLog('[OpenSpecParser] project.md not found');
      return undefined;
    }
  }

  /**
   * 解析 specs/ 目录下的所有 capabilities
   */
  private async parseCapabilities(
    openspecUri: vscode.Uri
  ): Promise<CapabilityInfo[]> {
    const capabilities: CapabilityInfo[] = [];
    const specsUri = vscode.Uri.joinPath(openspecUri, 'specs');

    try {
      const entries = await vscode.workspace.fs.readDirectory(specsUri);

      for (const [name, type] of entries) {
        if (type !== vscode.FileType.Directory) {
          continue;
        }

        const capabilityUri = vscode.Uri.joinPath(specsUri, name);
        const capability = await this.parseCapability(
          capabilityUri,
          name,
          openspecUri
        );
        if (capability) {
          capabilities.push(capability);
        }
      }
    } catch (error) {
      printLog(
        `[OpenSpecParser] Failed to read specs directory: ${getErrorMessage(error)}`
      );
    }

    return capabilities;
  }

  /**
   * 解析单个 capability
   */
  private async parseCapability(
    capabilityUri: vscode.Uri,
    id: string,
    openspecUri: vscode.Uri
  ): Promise<CapabilityInfo | null> {
    try {
      // 读取 spec.md
      const specMdUri = vscode.Uri.joinPath(capabilityUri, 'spec.md');
      const specFile = await this.readSpecFile(specMdUri, openspecUri);

      if (!specFile) {
        printLog(
          `[OpenSpecParser] No spec.md found for capability: ${id}`
        );
        return null;
      }

      const capability: CapabilityInfo = {
        id,
        name: id,
        specFile,
      };

      // 尝试读取 design.md (可选)
      const designMdUri = vscode.Uri.joinPath(capabilityUri, 'design.md');
      const designFile = await this.readSpecFile(designMdUri, openspecUri);
      if (designFile) {
        capability.designFile = designFile;
      }

      return capability;
    } catch (error) {
      printLog(
        `[OpenSpecParser] Failed to parse capability ${id}: ${getErrorMessage(error)}`
      );
      return null;
    }
  }

  /**
   * 解析 changes/ 目录下的活跃变更 (排除 archive)
   */
  private async parseActiveChanges(
    openspecUri: vscode.Uri
  ): Promise<ChangeInfo[]> {
    const changes: ChangeInfo[] = [];
    const changesUri = vscode.Uri.joinPath(openspecUri, 'changes');

    try {
      const entries = await vscode.workspace.fs.readDirectory(changesUri);

      for (const [name, type] of entries) {
        // 跳过 archive 目录和非目录项
        if (type !== vscode.FileType.Directory || name === 'archive') {
          continue;
        }

        const changeUri = vscode.Uri.joinPath(changesUri, name);
        const change = await this.parseChange(changeUri, name, openspecUri);
        if (change) {
          changes.push(change);
        }
      }
    } catch (error) {
      printLog(
        `[OpenSpecParser] Failed to read changes directory: ${getErrorMessage(error)}`
      );
    }

    return changes;
  }

  /**
   * 解析单个 change
   */
  private async parseChange(
    changeUri: vscode.Uri,
    id: string,
    openspecUri: vscode.Uri
  ): Promise<ChangeInfo | null> {
    try {
      // 读取 proposal.md (必需)
      const proposalUri = vscode.Uri.joinPath(changeUri, 'proposal.md');
      const proposalFile = await this.readSpecFile(proposalUri, openspecUri);

      if (!proposalFile) {
        printLog(
          `[OpenSpecParser] No proposal.md found for change: ${id}`
        );
        return null;
      }

      const change: ChangeInfo = {
        id,
        proposalFile,
        specFiles: [],
      };

      // 读取 tasks.md (可选)
      const tasksUri = vscode.Uri.joinPath(changeUri, 'tasks.md');
      const tasksFile = await this.readSpecFile(tasksUri, openspecUri);
      if (tasksFile) {
        change.tasksFile = tasksFile;
      }

      // 读取 design.md (可选)
      const designUri = vscode.Uri.joinPath(changeUri, 'design.md');
      const designFile = await this.readSpecFile(designUri, openspecUri);
      if (designFile) {
        change.designFile = designFile;
      }

      // 读取 specs/ 目录下的所有 .md 文件
      change.specFiles = await this.parseSpecFiles(changeUri, openspecUri);

      return change;
    } catch (error) {
      printLog(
        `[OpenSpecParser] Failed to parse change ${id}: ${getErrorMessage(error)}`
      );
      return null;
    }
  }

  /**
   * 解析 change 下的 specs/ 目录
   */
  private async parseSpecFiles(
    changeUri: vscode.Uri,
    openspecUri: vscode.Uri
  ): Promise<SpecFileInfo[]> {
    const specFiles: SpecFileInfo[] = [];
    const specsUri = vscode.Uri.joinPath(changeUri, 'specs');

    try {
      await this.collectMdFiles(specsUri, specFiles, openspecUri);
    } catch {
      // specs 目录可能不存在
    }

    return specFiles;
  }

  /**
   * 递归收集目录下的所有 .md 文件
   */
  private async collectMdFiles(
    dirUri: vscode.Uri,
    files: SpecFileInfo[],
    openspecUri: vscode.Uri
  ): Promise<void> {
    try {
      const entries = await vscode.workspace.fs.readDirectory(dirUri);

      for (const [name, type] of entries) {
        const entryUri = vscode.Uri.joinPath(dirUri, name);

        if (type === vscode.FileType.Directory) {
          // 递归进入子目录
          await this.collectMdFiles(entryUri, files, openspecUri);
        } else if (type === vscode.FileType.File && name.endsWith('.md')) {
          const file = await this.readSpecFile(entryUri, openspecUri);
          if (file) {
            files.push(file);
          }
        }
      }
    } catch {
      // 忽略无法访问的目录
    }
  }

  /**
   * 读取单个 spec 文件
   */
  private async readSpecFile(
    fileUri: vscode.Uri,
    openspecUri: vscode.Uri
  ): Promise<SpecFileInfo | null> {
    try {
      const [content, stat] = await Promise.all([
        vscode.workspace.fs.readFile(fileUri),
        vscode.workspace.fs.stat(fileUri),
      ]);

      // 计算相对于 openspec 目录的路径
      const relativePath = fileUri.fsPath
        .replace(openspecUri.fsPath, '')
        .replace(/\\/g, '/')
        .replace(/^\//, '');

      return {
        path: `${this.rootDirName}/${relativePath}`,
        name: fileUri.path.split('/').pop() || '',
        content: Buffer.from(content).toString('utf8'),
        lastModified: stat.mtime,
      };
    } catch {
      return null;
    }
  }
}

