  /**
   * 检测所有步骤的当前状态
   * 此方法使用静默模式检测，不会触发状态变更通知
   */
  public async detectSetupStatus(): Promise<SpecSetupStatus> {
    printLog('[SpecSetupHandler] 开始检测 setup 状态...');

    // 并行检测所有步骤 (使用静默模式)
    await Promise.all([
      // OpenSpec 检测 (2 步)
      this.checkOpenspecCli(true),
      this.checkOpenspecInit(true),
      // SpecKit 检测 (2 步)
      this.checkSpecifyCli(true),
      this.checkSpeckitInit(true),
    ]);

    printLog('[SpecSetupHandler] setup 状态检测完成');
    return this.setupStatus;
  }

  // ==================== CLI 安装方法 ====================

  /**
   * 安装 OpenSpec CLI (通过 VSCode Terminal)
   * 前置条件：Node.js 已安装且版本满足要求
   */
  private async installOpenspecCli(version: '0.23' | '1.x' = '0.23'): Promise<boolean> {
    // 根据版本确定安装的包名
    const packageName = version === '0.23'
      ? '@fission-ai/openspec@0.23.0'  // 固定版本
      : '@fission-ai/openspec@^1';     // 范围版本（获取最新 1.x）

    // 发送进度消息：正在安装
    this.updateOpenSpecStep('openspecCli', SpecSetupStepStatus.Running, {
      progressMessage: `正在安装 OpenSpec CLI (${version})...`,
    });
    printLog(`[SpecSetupHandler] 开始安装 OpenSpec CLI: ${packageName} (via Terminal)...`);

    try {
      // 通过 Terminal 执行安装命令，继承用户完整的 shell 环境
      const installResult = await runTerminalCommand(
        `npm install -g ${packageName}`,
        this.workspaceRoot,
        { timeout: 120000 } // 2 分钟超时
      );

      printLog(`[SpecSetupHandler] npm install 结果: success=${installResult.success}, output=${installResult.output}`);

      if (!installResult.success) {
        this.updateOpenSpecStep(
          'openspecCli',
          SpecSetupStepStatus.Failed,
          {
            errorCode: SpecSetupErrorCode.OPENSPEC_CLI_UNAVAILABLE,
            errorMessage: `安装 OpenSpec CLI 失败: ${installResult.error || '未知错误'}`,
          }
        );
        return false;
      }

      // 发送进度消息：正在验证安装
      this.updateOpenSpecStep('openspecCli', SpecSetupStepStatus.Running, {
        progressMessage: '正在验证安装...',
      });

      // 通过 Terminal 验证安装，检查输出是否包含有效版本号
      const verifyResult = await runTerminalCommand(
        'openspec --version',
        this.workspaceRoot,
        { timeout: 10000 }
      );

      if (verifyResult.success) {
        const version = extractVersion(verifyResult.output);
        if (version) {
          this.updateOpenSpecStep('openspecCli', SpecSetupStepStatus.Completed);
          printLog(`[SpecSetupHandler] OpenSpec CLI 安装成功: ${version}`);
          return true;
        }
        // 输出不包含有效版本号
        this.updateOpenSpecStep(
          'openspecCli',
          SpecSetupStepStatus.Failed,
          {
            errorCode: SpecSetupErrorCode.OPENSPEC_CLI_UNAVAILABLE,
            errorMessage: `安装后验证失败: 输出不包含有效版本号 - ${verifyResult.output.substring(0, 100)}`,
          }
        );
        return false;
      }

      // 验证命令执行失败
      this.updateOpenSpecStep(
        'openspecCli',
        SpecSetupStepStatus.Failed,
        {
          errorCode: SpecSetupErrorCode.OPENSPEC_CLI_UNAVAILABLE,
          errorMessage: `安装后验证失败: ${verifyResult.error || '无法执行 openspec --version'}`,
        }
      );
      return false;
    } catch (err) {
      this.updateOpenSpecStep(
        'openspecCli',
        SpecSetupStepStatus.Failed,
        {
          errorCode: SpecSetupErrorCode.OPENSPEC_CLI_UNAVAILABLE,
          errorMessage: `安装 OpenSpec CLI 异常: ${getErrorMessage(err)}`,
        }
      );
      return false;
    }
  }

