/**
 * SpecHandler - 管理仓库下的 spec 文件
 * 采用单例模式，提供 spec 文件的统一管理功能
 */
import * as vscode from 'vscode';
import { debounce, DebouncedFunc } from 'lodash';
import {
  SpecInfo,
  SpecHandlerOptions,
  FrameworkSpecInfo,
  SpecFramework,
  SpecSetupStatus,
} from './types';
import { getAllParsers } from './parsers';
import { SpecSetupHandler } from './setupHandler';
import { printLog } from '../logHandler/logHandler';
import getErrorMessage from '../../utils/getErrorMessage';
import { getWebviewProvider } from '../../provider/webviewProvider';
import { getReporter } from '../../utils/report';

/** 默认防抖延迟时间 (ms) */
const DEFAULT_DEBOUNCE_DELAY = 500;

/**
 * Spec 事件类型
 */
enum SpecEventType {
  CreateChange = 'Spec.create_change',
  CreateFeature = 'Spec.create_feature',
  ArchiveChange = 'Spec.archive_change',
}

/**
 * SpecHandler 类
 */
export class SpecHandler {
  private static instance: SpecHandler | null = null;
  private specInfo: SpecInfo | null = null;
  private fileWatchers: vscode.FileSystemWatcher[] = [];
  private disposables: vscode.Disposable[] = [];
  private isInitialized = false;
  private readonly enableWatcher: boolean;
  private readonly debounceDelay: number;
  private debouncedScan: DebouncedFunc<() => Promise<void>> | null = null;

  /** 已知的 OpenSpec change ID 集合 */
  private knownChanges: Set<string> = new Set();
  /** 已知的 SpecKit feature ID 集合 */
  private knownFeatures: Set<string> = new Set();
  /** 已知的 OpenSpec archive 目录名集合 */
  private knownArchives: Set<string> = new Set();

  /** Setup Handler 实例 */
  private setupHandler: SpecSetupHandler | null = null;

  private constructor(options: SpecHandlerOptions = {}) {
    this.enableWatcher = options.enableWatcher !== false;
    this.debounceDelay = options.debounceDelay || DEFAULT_DEBOUNCE_DELAY;

    printLog(
      `[SpecHandler] Instance created - enableWatcher: ${this.enableWatcher}, debounceDelay: ${this.debounceDelay}`
    );
  }

  /**
   * 获取 SpecHandler 单例实例
   */
  public static getInstance(options?: SpecHandlerOptions): SpecHandler {
    if (!SpecHandler.instance) {
      SpecHandler.instance = new SpecHandler(options);
    }
    return SpecHandler.instance;
  }

  /**
   * 初始化 SpecHandler
   */
  public async initialize(): Promise<void> {
    if (this.isInitialized) {
      printLog('[SpecHandler] Already initialized');
      return;
    }

    try {
      printLog('[SpecHandler] Starting initialization...');

      // 创建防抖的扫描函数
      this.debouncedScan = debounce(async () => {
        await this.scanAndSync();
      }, this.debounceDelay);

      // 执行首次扫描
      await this.scanSpecs();

      // 检测 setup 状态并合并到 specInfo
      await this.detectSetupStatus();

      // 同步到 Webview
      this.syncSpecInfo();

      // 启用文件监听
      if (this.enableWatcher) {
        this.initializeFileWatchers();
      }

      this.isInitialized = true;
      printLog(
        `[SpecHandler] Initialization completed - frameworks: ${this.specInfo?.frameworks.length || 0}`
      );
    } catch (error) {
      const errorMessage = getErrorMessage(error);
      printLog(`[SpecHandler] Initialization failed - error: ${errorMessage}`);
      throw new Error(`Failed to initialize SpecHandler: ${errorMessage}`);
    }
  }

  /**
   * 扫描工作区中的所有 spec 框架
   * @param detectEvents 是否检测并上报事件 (首次扫描时为 false)
   */
  public async scanSpecs(detectEvents = false): Promise<SpecInfo> {
    printLog('[SpecHandler] Scanning specs...');

    const frameworks: FrameworkSpecInfo[] = [];
    const workspaceFolders = vscode.workspace.workspaceFolders;

    if (!workspaceFolders || workspaceFolders.length === 0) {
      printLog('[SpecHandler] No workspace folders found');
      this.specInfo = {
        frameworks: [],
        lastScanTime: Date.now(),
      };
      return this.specInfo;
    }

    // 目前只处理第一个工作区
    const workspaceRoot = workspaceFolders[0].uri;
    const parsers = getAllParsers();

    // 并行检测和解析所有框架
    const parsePromises = parsers.map(async (parser) => {
      try {
        const detected = await parser.detect(workspaceRoot);
        if (detected) {
          printLog(
            `[SpecHandler] Detected framework: ${parser.framework}`
          );
          return await parser.parse(workspaceRoot);
        }
      } catch (error) {
        printLog(
          `[SpecHandler] Error detecting/parsing ${parser.framework}: ${getErrorMessage(error)}`
        );
      }
      return null;
    });

    const results = await Promise.all(parsePromises);
    for (const result of results) {
      if (result) {
        frameworks.push(result);
      }
    }

    // 扫描归档目录
    const currentArchives = await this.scanArchiveDirectory(workspaceRoot);

    this.specInfo = {
      frameworks,
      lastScanTime: Date.now(),
    };

    // 检测并上报事件
    if (detectEvents) {
      this.detectAndReportEvents(frameworks, currentArchives);
    }

    // 更新已知状态
    this.updateKnownState(frameworks, currentArchives);

    printLog(
      `[SpecHandler] Scan completed - frameworks: ${frameworks.length}`
    );

    return this.specInfo;
  }

  /**
   * 扫描 OpenSpec 归档目录
   */
  private async scanArchiveDirectory(
    workspaceRoot: vscode.Uri
  ): Promise<Set<string>> {
    const archives = new Set<string>();
    const archiveUri = vscode.Uri.joinPath(
      workspaceRoot,
      'openspec',
      'changes',
      'archive'
    );

    try {
      const entries = await vscode.workspace.fs.readDirectory(archiveUri);
      for (const [name, type] of entries) {
        if (type === vscode.FileType.Directory) {
          archives.add(name);
        }
      }
    } catch {
      // archive 目录可能不存在
    }

    return archives;
  }

  /**
   * 检测并上报 Spec 事件
   */
  private detectAndReportEvents(
    frameworks: FrameworkSpecInfo[],
    currentArchives: Set<string>
  ): void {
    // 检测新增的 OpenSpec changes
    const openspecFramework = frameworks.find(
      (f) => f.framework === SpecFramework.OpenSpec
    );
    if (openspecFramework?.activeChanges) {
      for (const change of openspecFramework.activeChanges) {
        if (!this.knownChanges.has(change.id)) {
          this.reportSpecEvent(SpecEventType.CreateChange, {
            change_id: change.id,
          });
        }
      }
    }

    // 检测新增的 SpecKit features
    const speckitFramework = frameworks.find(
      (f) => f.framework === SpecFramework.SpecKit
    );
    if (speckitFramework?.features) {
      for (const feature of speckitFramework.features) {
        if (!this.knownFeatures.has(feature.id)) {
          this.reportSpecEvent(SpecEventType.CreateFeature, {
            feature_id: feature.id,
            feature_name: feature.name,
          });
        }
      }
    }

    // 检测新增的归档目录
    for (const archiveName of currentArchives) {
      if (!this.knownArchives.has(archiveName)) {
        this.reportSpecEvent(SpecEventType.ArchiveChange, {
          archive_name: archiveName,
        });
      }
    }
  }

  /**
   * 更新已知状态
   */
  private updateKnownState(
    frameworks: FrameworkSpecInfo[],
    currentArchives: Set<string>
  ): void {
    // 更新已知的 OpenSpec changes
    this.knownChanges.clear();
    const openspecFramework = frameworks.find(
      (f) => f.framework === SpecFramework.OpenSpec
    );
    if (openspecFramework?.activeChanges) {
      for (const change of openspecFramework.activeChanges) {
        this.knownChanges.add(change.id);
      }
    }

    // 更新已知的 SpecKit features
    this.knownFeatures.clear();
    const speckitFramework = frameworks.find(
      (f) => f.framework === SpecFramework.SpecKit
    );
    if (speckitFramework?.features) {
      for (const feature of speckitFramework.features) {
        this.knownFeatures.add(feature.id);
      }
    }

    // 更新已知的归档目录
    this.knownArchives = new Set(currentArchives);
  }

  /**
   * 上报 Spec 事件
   */
  private reportSpecEvent(
    event: SpecEventType,
    data: Record<string, string>
  ): void {
    try {
      const reporter = getReporter();
      if (reporter) {
        reporter.appendMessage({
          event,
          message: `Spec event: ${event}`,
          extends: data,
        });
        printLog(
          `[SpecHandler] Reported event: ${event} - data: ${JSON.stringify(data)}`
        );
      }
    } catch (error) {
      printLog(
        `[SpecHandler] Failed to report event: ${getErrorMessage(error)}`
      );
    }
  }

  /**
   * 获取当前的 spec 信息
   * 确保返回的数据包含最新的 setupStatus
   */
  public getSpecInfo(): SpecInfo | null {
    if (this.specInfo && this.setupHandler) {
      // 确保 setupStatus 是最新的
      this.specInfo.setupStatus = this.setupHandler.getSetupStatus();
    }
    return this.specInfo;
  }

  /**
   * 同步 spec 信息到 Webview
   * 确保在发送前合并最新的 setupStatus
   */
  public syncSpecInfo(panelId?: string): void {
    const webviewProvider = getWebviewProvider();
    if (webviewProvider) {
      // 确保 setupStatus 是最新的
      if (this.specInfo && this.setupHandler) {
        this.specInfo.setupStatus = this.setupHandler.getSetupStatus();
      }

      printLog(`[SpecHandler] syncSpecInfo - panelId: ${panelId}, hasSpecInfo: ${!!this.specInfo}`);

      // 使用通用路由方法发送消息
      webviewProvider.sendMessageWithRouting(
        {
          type: 'SYNC_SPEC_INFO',
          data: this.specInfo,
        },
        panelId
      );
    } else {
      printLog('[SpecHandler] Webview provider not available');
    }
  }

  /**
   * 扫描并同步 (用于文件变化时)
   * 文件变化触发时启用事件检测
   */
  private async scanAndSync(): Promise<void> {
    const prevFrameworks = new Set(this.specInfo?.frameworks.map(f => f.framework));
    await this.scanSpecs(true);
    const currFrameworks = new Set(this.specInfo?.frameworks.map(f => f.framework));

    // 当有框架消失时（目录被外部删除）重新检测环境状态
    // 框架新增时无需检测，setup 流程已自行管理状态
    const hasFrameworkRemoved = [...prevFrameworks].some(f => !currFrameworks.has(f));
    if (hasFrameworkRemoved) {
      await this.detectSetupStatus();
    }

    this.syncSpecInfo();
  }

  /**
   * 初始化文件监听器
   */
  private initializeFileWatchers(): void {
    const workspaceFolders = vscode.workspace.workspaceFolders;
    if (!workspaceFolders || workspaceFolders.length === 0) {
      return;
    }

    const workspaceRoot = workspaceFolders[0].uri;
    const parsers = getAllParsers();

    // 为每个框架创建文件监听器
    for (const parser of parsers) {
      // 监听根目录本身的创建/删除（解决整个目录被删时子文件 watcher 无法触发的问题）
      this.createFileWatcher(
        workspaceRoot,
        parser.rootDirName,
        parser.framework,
        'root-dir'
      );

      // 主配置目录监听 (如 openspec/**/*.md 或 .specify/**/*.md)
      this.createFileWatcher(
        workspaceRoot,
        `${parser.rootDirName}/**/*.md`,
        parser.framework
      );

      // OpenSpec 需要额外监听归档目录
      if (parser.framework === SpecFramework.OpenSpec) {
        this.createFileWatcher(
          workspaceRoot,
          'openspec/changes/archive/**/*.md',
          parser.framework,
          'archive'
        );
      }

      // SpecKit 需要额外监听 specs/ 业务规格目录
      if (parser.framework === SpecFramework.SpecKit) {
        this.createFileWatcher(
          workspaceRoot,
          'specs/**/*.md',
          parser.framework,
          'specs'
        );
      }
    }
  }

  /**
   * 创建单个文件监听器
   */
  private createFileWatcher(
    workspaceRoot: vscode.Uri,
    pattern: string,
    framework: SpecFramework,
    label?: string
  ): void {
    const watchPattern = new vscode.RelativePattern(workspaceRoot, pattern);
    const watcher = vscode.workspace.createFileSystemWatcher(watchPattern);

    // 监听创建、修改、删除事件
    watcher.onDidCreate(this.onFileChanged.bind(this));
    watcher.onDidChange(this.onFileChanged.bind(this));
    watcher.onDidDelete(this.onFileChanged.bind(this));

    this.fileWatchers.push(watcher);
    this.disposables.push(watcher);

    const logLabel = label ? `${framework}/${label}` : framework;
    printLog(
      `[SpecHandler] File watcher initialized for ${logLabel} - pattern: ${pattern}`
    );
  }

  /**
   * 处理文件变化事件
   */
  private onFileChanged(uri: vscode.Uri): void {
    printLog(`[SpecHandler] File changed - path: ${uri.fsPath}`);

    // 使用防抖函数触发扫描
    if (this.debouncedScan) {
      this.debouncedScan();
    }
  }

  /**
   * 检查是否已初始化
   */
  public get initialized(): boolean {
    return this.isInitialized;
  }

  // ==================== Setup 相关方法 ====================

  /**
   * 获取 SpecSetupHandler 实例
   */
  private getOrCreateSetupHandler(): SpecSetupHandler | null {
    const workspaceFolders = vscode.workspace.workspaceFolders;
    if (!workspaceFolders || workspaceFolders.length === 0) {
      printLog('[SpecHandler] No workspace folders found for setup handler');
      return null;
    }

    if (!this.setupHandler) {
      const workspaceRoot = workspaceFolders[0].uri.fsPath;
      this.setupHandler = new SpecSetupHandler(workspaceRoot, () => {
        // 状态变更时同步到 Webview
        this.syncSetupStatusToSpecInfo();
      });
    }
    return this.setupHandler;
  }

  /**
   * 将 setup 状态同步到 specInfo 并发送到 Webview
   */
  private syncSetupStatusToSpecInfo(): void {
    if (this.setupHandler && this.specInfo) {
      this.specInfo.setupStatus = this.setupHandler.getSetupStatus();
      this.syncSpecInfo();
    }
  }

  /**
   * 检测 Setup 状态
   */
  public async detectSetupStatus(): Promise<SpecSetupStatus | null> {
    const handler = this.getOrCreateSetupHandler();
    if (!handler) {
      return null;
    }

    const status = await handler.detectSetupStatus();
    this.syncSetupStatusToSpecInfo();
    return status;
  }

  /**
   * 执行 OpenSpec Setup 流程
   * @param version - OpenSpec 版本 ('0.23' | '1.x')，默认 '0.23'
   * @returns 是否成功
   */
  public async runOpenspecSetup(version: '0.23' | '1.x' = '0.23'): Promise<boolean> {
    const handler = this.getOrCreateSetupHandler();
    if (!handler) {
      printLog('[SpecHandler] Cannot run OpenSpec setup: no workspace');
      return false;
    }

    printLog('[SpecHandler] Starting OpenSpec setup...');
    const success = await handler.runOpenspecSetup(version);

    // 无论成功与否，都重新扫描 spec 并同步状态
    if (success) {
      await this.scanSpecs(true);
    }
    this.syncSetupStatusToSpecInfo();

    return success;
  }

  /**
   * 执行 SpecKit Setup 流程
   * @returns 是否成功
   */
  public async runSpeckitSetup(): Promise<boolean> {
    const handler = this.getOrCreateSetupHandler();
    if (!handler) {
      printLog('[SpecHandler] Cannot run SpecKit setup: no workspace');
      return false;
    }

    printLog('[SpecHandler] Starting SpecKit setup...');
    const success = await handler.runSpeckitSetup();

    // 无论成功与否，都重新扫描 spec 并同步状态
    if (success) {
      await this.scanSpecs(true);
    }
    this.syncSetupStatusToSpecInfo();

    return success;
  }

  /**
   * 执行 OpenSpec 升级流程 (0.23 -> 1.x)
   * @returns 升级后的版本号，失败则返回 null
   */
  public async runOpenspecUpgrade(): Promise<string | null> {
    const handler = this.getOrCreateSetupHandler();
    if (!handler) {
      printLog('[SpecHandler] Cannot run OpenSpec upgrade: no workspace');
      return null;
    }

    printLog('[SpecHandler] Starting OpenSpec upgrade (0.23 -> 1.x)...');
    const upgradedVersion = await handler.runOpenspecUpgrade();

    // 无论成功与否都同步一次状态
    if (upgradedVersion) {
      await this.scanSpecs(true);
    }
    this.syncSetupStatusToSpecInfo();
    return upgradedVersion;
  }

  /**
   * 获取当前的 setup 状态
   */
  public getSetupStatus(): SpecSetupStatus | null {
    return this.setupHandler?.getSetupStatus() || null;
  }

  /**
   * 释放资源
   */
  public dispose(): void {
    printLog('[SpecHandler] Disposing resources...');

    // 清理文件监听器
    this.fileWatchers.forEach((watcher) => watcher.dispose());
    this.fileWatchers = [];

    // 清理其他 disposables
    this.disposables.forEach((disposable) => disposable.dispose());
    this.disposables = [];

    // 重置状态
    this.specInfo = null;
    this.isInitialized = false;
    this.debouncedScan = null;

    // 清理已知状态集合
    this.knownChanges.clear();
    this.knownFeatures.clear();
    this.knownArchives.clear();

    // 重置单例实例
    SpecHandler.instance = null;

    printLog('[SpecHandler] Resources disposed');
  }
}

// ==================== 导出便利函数 ====================

let specHandler: SpecHandler | null = null;

/**
 * 初始化 SpecHandler
 * @param context VSCode 扩展上下文
 * @param options 配置选项
 */
export async function initSpecHandler(
  context: vscode.ExtensionContext,
  options?: SpecHandlerOptions
): Promise<SpecHandler> {
  specHandler = SpecHandler.getInstance(options);
  await specHandler.initialize();

  // 注册到 context.subscriptions 以便自动清理
  context.subscriptions.push({
    dispose: () => {
      if (specHandler) {
        specHandler.dispose();
        specHandler = null;
      }
    },
  });

  return specHandler;
}

/**
 * 获取 SpecHandler 实例
 */
export function getSpecHandler(): SpecHandler | null {
  return specHandler;
}

/**
 * 销毁 SpecHandler
 */
export function disposeSpecHandler(): void {
  if (specHandler) {
    specHandler.dispose();
    specHandler = null;
  }
}

export default SpecHandler;

