function generateConflictText(oldText: string, newText: string): string {
  let result = '';
  let trimOldText = oldText.trim();
  trimOldText = trimOldText.endsWith('\n') ? trimOldText : `${trimOldText}\n`;
  let trimNewText = newText.trim();
  trimNewText = trimNewText.endsWith('\n') ? trimNewText : `${trimNewText}\n`;
  const diffs = diffLines(trimOldText, trimNewText);
  let tempDiff:
    | {
      added?: boolean;
      removed?: boolean;
      value: string;
    }
    | undefined;

  for (const diff of diffs) {
    if (diff.added) {
      if (tempDiff && tempDiff.removed) {
        result += `<<<<<<< old\n${tempDiff.value}=======\n${diff.value}>>>>>>> new\n`;
        tempDiff = undefined;
      } else {
        tempDiff = diff;
      }
    } else if (diff.removed) {
      if (tempDiff && tempDiff.added) {
        result += `<<<<<<< old\n${diff.value}=======\n${tempDiff.value}>>>>>>> new\n`;
        tempDiff = undefined;
      } else {
        tempDiff = diff;
      }
    } else {
      if (tempDiff) {
        if (tempDiff.added) {
          result += `<<<<<<< old\n=======\n${tempDiff.value}>>>>>>> new\n`;
        } else if (tempDiff.removed) {
          result += `<<<<<<< old\n${tempDiff.value}=======\n>>>>>>> new\n`;
        }
        tempDiff = undefined;
      }
      result += `${diff.value}`;
    }
  }
  if (tempDiff) {
    if (tempDiff.added) {
      result += `<<<<<<< old\n=======\n${tempDiff.value}>>>>>>> new\n`;
    } else if (tempDiff.removed) {
      result += `<<<<<<< old\n${tempDiff.value}=======\n>>>>>>> new\n`;
    }
  }
  return result;
}

const archiver = require('archiver');
const FormData = require('form-data');

/**
 * 智能拼接路径，处理重叠部分
 * @param basePath 基础路径（工作空间路径）
 * @param relativePath 相对路径（可能包含重叠部分）
 * @returns 正确拼接后的绝对路径
 */
function smartJoinPath(basePath: string, relativePath: string): string {
  // 标准化路径分隔符
  const normalizedBase = basePath.replace(/\\/g, '/');
  const normalizedRelative = relativePath.replace(/\\/g, '/');

  // 分割路径为数组
  const baseParts = normalizedBase.split('/').filter(p => p);
  const relativeParts = normalizedRelative.split('/').filter(p => p);

  // 查找最长的重叠部分
  let maxOverlapLength = 0;

  for (let i = 1; i <= Math.min(baseParts.length, relativeParts.length); i++) {
    const baseEnd = baseParts.slice(-i);
    const relativeStart = relativeParts.slice(0, i);

    if (JSON.stringify(baseEnd) === JSON.stringify(relativeStart)) {
      maxOverlapLength = i;
    }
  }

  // 如果找到重叠部分，去除重叠后拼接
  if (maxOverlapLength > 0) {
    const uniqueRelativeParts = relativeParts.slice(maxOverlapLength);
    const result = [...baseParts, ...uniqueRelativeParts].join('/');
    return result;
  }

  // 没有重叠，直接拼接
  return [...baseParts, ...relativeParts].join('/');
}

/**
 * 计算文件的绝对路径（处理重叠路径）
 * @param relativePath 相对路径
 * @returns 绝对路径
 */
export function getRelativePathToWorkspace(relativePath: string): string | undefined {
  const workspaceFolders = vscode.workspace.workspaceFolders;

  if (!workspaceFolders || workspaceFolders.length === 0) {
    vscode.window.showErrorMessage('未打开工作空间');
    return undefined;
  }

  // 获取工作空间根目录
  const workspaceRoot = workspaceFolders[0].uri.fsPath;

  // 标准化路径分隔符
  const normalizedFilePath = relativePath.replace(/\\/g, '/');
  const normalizedWorkspaceRoot = workspaceRoot.replace(/\\/g, '/');

  if (!workspaceFolders || workspaceFolders.length === 0) {
    vscode.window.showErrorMessage('未打开工作空间');
    return undefined;
  }

  // 使用智能拼接
  const absolutePath = smartJoinPath(normalizedWorkspaceRoot, normalizedFilePath);

  // 计算相对路径
  const res = path.relative(normalizedWorkspaceRoot, absolutePath);

  // 标准化路径分隔符为正斜杠
  return res.replace(/\\/g, '/');
}

