  public async handleMessage(message: any, webviewView: vscode.Webview) {
    const codeSearchManager = CodeSearchManager.getInstance(webviewView);
    const catchEdit = ActiveTextEditorCache.getInstance().getCachedEditor();
    switch (message.type) {
      case 'WEBVIEW_ACK': {
        const { event, payload } = message.data ?? {};
        if (typeof event === 'string') {
          this.webviewEventEmitter.fire({ type: event, payload });
        }
        if (message.data?.event === 'app_init') {
          this.isReady = true;
        }
        break;
      }
      case 'COPY_TO_CLIPBOARD': {
        vscode.env.clipboard.writeText(message.data);
