        // 获取当前光标选中行的开始和结束位置
        const selection = new vscode.Selection(
          editor.selection.start.line,
          0,
          editor.selection.end.line,
          editor.document.lineAt(editor.selection.end.line).text.length
        );
        // 获取当前光标选中行的文本
