          const listData = listResult.status === 'fulfilled' ? listResult.value : null;
          const codeTextsData = codeTextsResult.status === 'fulfilled' ? codeTextsResult.value : null;

          // 为 codeTextsData 中的项目添加 codemaker_public 标识
          if (codeTextsData?.items) {
            codeTextsData.items = codeTextsData.items.map((item: any) => ({
              ...item,
              codemaker_public: true
