          if (listData?.items) {
            listData.items = listData.items.map((item: any) => ({
              ...item,
              codemaker_public: false
            }));
          }

          function mergeAndDeduplicateByCode(dataList: any[]) {
            const allItems = dataList.flatMap(data => data.items);
            const uniqueMap = new Map();

            allItems.forEach(item => {
              if (item.code) {
                // 如果已存在相同code的项目，优先保留 codemaker_public: true 的数据
                if (!uniqueMap.has(item.code) || item.codemaker_public) {
                  uniqueMap.set(item.code, item);
                }
              }
            });

            const uniqueItems = Array.from(uniqueMap.values());

            return {
              items: uniqueItems,
              total: uniqueItems.length
            };
          }

          const deduplicatedData = mergeAndDeduplicateByCode([
            listData || { items: [], total: 0 },
            codeTextsData || { items: [], total: 0 }
          ]);

