          });
        }
        break;
      case 'CODESCAN_INDEX_WORKSPACE': {
        const { options } = message.data || {};
        initWorkspaceDirIndex(options);
        break;
      }
      case 'GET_CODESCAN_INDEX_STATUS': {
        const status = getIndexingStatus();
        this.sendWebviewMessage({
          type: 'CODESCAN_INDEX_STATUS',
          data: status,
        });
        break;
      }
      case 'OPEN_CODESCAN_ISSUE': {
        const startTime = Date.now();
        const { file, issue, task, context } = message.data;
        const { filePath, startLine, endLine, startCharacter, endCharacter } =
          file || {};
        this.sendWebviewMessage({ type: 'OPEN_CODESCAN_ISSUE_START' });

        const rootPath = vscode.workspace.rootPath || '';
        printLog(
          `[CodeScan] Open CodeScan Issue: ${JSON.stringify({
            rootPath,
            filePath,
            task,
            issue,
          })}`
        );

        let fileUri: vscode.Uri | null = null;
        let lineOffset = 0;
        const params = {
          ...issue,
          isInWorkspace: false,
        };

        if (!context?.content || !issue?.lineHash) {
          printLog(`[CodeScan] 问题上下文或行哈希为空，跳过查找文件`);
          openCodeScanIssuePanel(
            this.extensionContext as vscode.ExtensionContext,
            params
          );
          this.sendWebviewMessage({ type: 'OPEN_CODESCAN_ISSUE_FINISH' });
          return;
        }

        // SVN 项目优先使用外链和 svn info 信息来查找
        if (task?.repoType === 'svn') {
          const branch = ['develop', 'dynamic'].includes(task?.scanMode) ? issue?.branch : '';
          const fullPath = getCompleteSvnUrl(task?.masterBanch, branch, filePath);
          if (fullPath) {
            printLog(`[CodeScan] 文件完整路径: ${fullPath}`);

            // 先检查外链
            const externalLink = findFileInExternalLink(fullPath);
            if (externalLink && existsSync(externalLink)) {
              printLog(`[CodeScan] 文件匹配到外链: ${externalLink}`);
              const matchLine = await compareIssueLine(externalLink, startLine, issue.lineHash, context.content, context.offset);
              printLog(`[CodeScan] 外链文件上下文匹配状态: ${!!matchLine}`);
              if (matchLine) {
                fileUri = vscode.Uri.file(externalLink);
                lineOffset = matchLine.offset;
              }
            }

            // 再检查 svn info 信息
            const svnLink = findFineInSvnLink(fullPath);
            if (svnLink && existsSync(svnLink)) {
              printLog(`[CodeScan] 在 SVN 仓库中找到文件: ${svnLink}`);
              const matchLine = await compareIssueLine(svnLink, startLine, issue.lineHash, context.content, context.offset);
              printLog(`[CodeScan] SVN 仓库文件上下文匹配状态: ${!!matchLine}`);
              if (matchLine) {
                fileUri = vscode.Uri.file(svnLink);
                lineOffset = matchLine.offset;
              }
            }
          }
        }

        // 兜底在本地目录查找
        if (!fileUri) {
          try {
            // 将根目录也作为一个子目录来处理
            const allDirs = ['', ...getWorkspaceDirIndex()];
            for (const dir of allDirs) {
              const fullPath = path.join(rootPath, dir, filePath);
              if (existsSync(fullPath)) {
                const matchLine = await compareIssueLine(fullPath, startLine, issue.lineHash, context.content, context.offset);
                if (matchLine) {
                  fileUri = vscode.Uri.file(fullPath);
                  lineOffset = matchLine.offset;
                  printLog(`[CodeScan] 在 ${dir || '根'} 目录中找到文件: ${fullPath}`);
                  break;
                }
              }
            }
          } catch (error) {
            printLog(`[CodeScan] 查找文件失败: ${getErrorMessage(error)}`);
          }
        }

        printLog(
          `[CodeScan] 文件查找结果: 文件${fileUri ? '存在' : '不存在'}，耗时${(Date.now() - startTime) / 1000}S`
        );

        if (fileUri) {
          params.isInWorkspace = true;
          vscode.window
            .showTextDocument(fileUri, {
              viewColumn: vscode.ViewColumn.One,
              preserveFocus: false,
            })
            .then((editor: vscode.TextEditor) => {
              const range = new vscode.Range(
                startLine + lineOffset,
                startCharacter,
                endLine + lineOffset,
                endCharacter
              );
              editor.selection = new vscode.Selection(range.start, range.end);
              // 滚动到指定范围
              editor.revealRange(range, vscode.TextEditorRevealType.AtTop);
            })
            .then(() => {
              openCodeScanIssuePanel(
                this.extensionContext as vscode.ExtensionContext,
                params
              );
              this.sendWebviewMessage({ type: 'OPEN_CODESCAN_ISSUE_FINISH' });
            });
        } else {
          openCodeScanIssuePanel(
            this.extensionContext as vscode.ExtensionContext,
            params
          );
          this.sendWebviewMessage({ type: 'OPEN_CODESCAN_ISSUE_FINISH' });
        }
        break;
      }
      case 'GIT_CHECKOUT_BRANCH': {
        const { branch } = message.data;
        try {
          const workspaceFolder = vscode.workspace.workspaceFolders?.[0];
          const workspacePath = workspaceFolder?.uri.fsPath;
          if (!workspacePath) {
            throw new Error('未找到工作区');
          }

          const currentBranchResult = await execCommand('git rev-parse --abbrev-ref HEAD', workspacePath);
          if (currentBranchResult.code === 0) {
            const currentBranch = currentBranchResult.stdout;
            if (currentBranch === branch) {
              vscode.window.showInformationMessage(`当前已经在 ${branch} 分支上`);
              return;
            }
          }

          // 执行 git fetch 获取最新分支
          const fetchResult = await vscode.window.withProgress(
            {
              location: vscode.ProgressLocation.Notification,
              title: '正在获取最新分支...',
              cancellable: false
            },
            () => execCommand('git fetch', workspacePath)
          );

          if (fetchResult.code !== 0) {
            throw new Error(`获取分支失败，错误信息：${fetchResult.stderr}`);
          }

          // 切换到目标分支
          const checkoutResult = await vscode.window.withProgress(
            {
              location: vscode.ProgressLocation.Notification,
              title: `正在切换到 ${branch} 分支...`,
              cancellable: false
            },
            () => execCommand(`git checkout ${branch}`, workspacePath)
          );

          if (checkoutResult.code !== 0) {
            throw new Error(`错误信息：${checkoutResult.stderr}`);
          }

          vscode.window.showInformationMessage(`已成功切换到 ${branch} 分支`);
        } catch (error) {
          const errorMessage = getErrorMessage(error);
          vscode.window.showErrorMessage(`切换分支失败，${errorMessage}`);
        }
        break;
      }
      case "CONSOLE_ERROR":
        const consoleErrorMessageData = message.data;
        if (Array.isArray(consoleErrorMessageData)) {
          console.error('[WEBVIEW-PROVIDER]', ...consoleErrorMessageData);
        }
        break;
      case "REPORT_CONSOLE_ERROR":
        const reportConsoleErrorMessageData = message.data;
        if (Array.isArray(reportConsoleErrorMessageData)) {
          hub.withScope((scope) => {
            scope.setTag('source', 'webview-provider');
            logger.captureMessage('[WEBVIEW-PROVIDER]' + reportConsoleErrorMessageData.join(''), Level.ERROR);
          });

        } else if ("message" in reportConsoleErrorMessageData
          && typeof reportConsoleErrorMessageData.message === 'string'
        ) {
          reportConsoleErrorMessageData.message = '[WEBVIEW-PROVIDER]' + reportConsoleErrorMessageData.message;
          if ("componentStack" in reportConsoleErrorMessageData) {
            hub.withScope((scope) => {
              scope.setExtra('componentStack', reportConsoleErrorMessageData.componentStack);
              scope.setTag('source', 'webview-provider');
              logger.captureException(reportConsoleErrorMessageData);
            });
          }
          else hub.withScope((scope) => {
            scope.setTag('source', 'webview-provider');
            logger.captureException(reportConsoleErrorMessageData);
          })
        }
        break;
      case 'CONSOLE_LOG':
        const consoleLogMessageData = message.data;
        if (Array.isArray(consoleLogMessageData)) {
          console.log('[WEBVIEW_PROVIDER]', ...message.data);
        }
        break;
      case 'PRINT_LOG':
