  public showWebview() {
    if (this._view) {
      this._view.show?.(true);
    } else {
      vscode.commands.executeCommand('codeMaker.webView.focus');
    }
  }

  private sendMessageToPanel(message: any) {
    if (this._panel && this.panelInit) {
      this._panel.webview.postMessage(message);
    } else {
      this.panelLeftOverMessages.push(message);
    }
  }

  private sendMessageToWebview(message: any) {
    if (this._view && this.hasInit) {
      this._view.webview.postMessage(message);
    } else {
      this.leftOverMessages.push(message);
    }
  }
  public sendWebviewMessage(
    message: any,
    config?: {
      show?: boolean;
      // 是否全部发送，如果不是全部发送，优先发给 panel
      targetType?: 'all' | 'primary';
    }
  ) {
    const targetType = config?.targetType || this.getDefaultTargetType(message.type);
    if (targetType === 'all') {
      this.sendMessageToPanel(message);
      this.sendMessageToWebview(message);
      this.broadcastToCodebasePanels(message);
    } else {
      if (this._panel) {
        this.sendMessageToPanel(message);
      } else {
        if (config?.show) {
          this.showWebview();
        }
        this.sendMessageToWebview(message);
      }
    }
  }

  /**
   * 通用的消息路由方法 - 根据 panelId 智能路由消息到正确的窗口
   *
   * @param message 要发送的消息对象
   * @param panelId 可选的目标 panelId
   *   - 如果提供了 panelId，尝试发送到指定的并行会话窗口
   *   - 如果 panelId 不存在或未提供，则广播到所有窗口
   *
   * 使用场景:
   *   - Handler 层需要响应 GET_XXX 请求时
   *   - 需要同步数据到特定窗口或所有窗口时
   */
  public sendMessageWithRouting(message: any, panelId?: string): void {
    if (panelId) {
      import('../../utils/CodebaseChatPanelManager')
        .then(({ CodebaseChatPanelManager }) => {
          try {
            if (CodebaseChatPanelManager.hasInstance()) {
              const panelManager = CodebaseChatPanelManager.getInstance();
              if (panelManager.hasPanel(panelId)) {
                panelManager.postToPanel(panelId, message);
              } else {
                this.sendWebviewMessage(message);
              }
            } else {
              this.sendWebviewMessage(message);
            }
          } catch (error) {
            printLog(`[WebviewProvider] Message routing error: ${getErrorMessage(error)}, fallback to primary`);
            this.sendWebviewMessage(message);
          }
        })
        .catch((error) => {
          printLog(`[WebviewProvider] Failed to load CodebaseChatPanelManager: ${getErrorMessage(error)}`);
          this.sendWebviewMessage(message);
        });
    } else {
      printLog(`[WebviewProvider] Broadcasting message to all windows, type: ${message.type}`);
      this.sendWebviewMessage(message, { targetType: 'all' });
    }
  }

  private broadcastToCodebasePanels(message: any) {
    try {
      import('../../utils/CodebaseChatPanelManager').then(({ CodebaseChatPanelManager }) => {
        // 只有在已初始化时才广播
        if (CodebaseChatPanelManager.hasInstance()) {
          const panelManager = CodebaseChatPanelManager.getInstance();
          panelManager.broadcastToAllPanels(message);
        }
      }).catch(() => {
        // 忽略导入错误
      });
    } catch {
      // 忽略错误
    }
  }

  private getDefaultTargetType(messageType: string): 'all' | 'primary' {
    // 初始化或者其他一些需要两边都发送的信息，统一在这里管理
    const systemMessages = [
      'setExtensionData', 'INIT_DATA', 'SYNC_WORKSPACE_INFO', 'sendReviewData', 'SYNC_WORKSPACE_LIST',
      'LOCAL_REVIEW_CONFIG', 'SYNC_MCP_SERVERS', 'EDITOR_FILE_STATE', 'WEBVIEW_BROADCAST',
      'APPLY_KEYBOARD_PASTE', 'ON_GET_WORKSPACE_PROBLEMS'
    ];
    return systemMessages.includes(messageType) ? 'all' : 'primary';
  }

  public sendPanelMessage(message: any) {
    if (this._panel && this.panelInit) {
      this._panel.webview.postMessage(message);
    } else {
      this.panelLeftOverMessages.push(message);
    }
  }

  private _getHtmlForWebview(webview: vscode.Webview) {
    const origin = WEBVIEW_URL;
    const hash = new Date().getTime();
    const iframeUrl = `${WEBVIEW_URL}?hash=${hash || ''}`;
    const codeServerUrl = (getCodeMakerConfig('CodeServerUrl') as string) || '';
    let validOrigin = '';
    try {
      const urlObj = new URL(codeServerUrl);
      validOrigin = urlObj.origin;
    } catch (err) {
      printLog(`CodeServerUrl 格式不正确，${getErrorMessage(err)}`);
    }

    return `<!DOCTYPE html>
            <html lang="en">
              <head>
                <meta charset="UTF-8" />
                <meta name="viewport" content="width=device-width, initial-scale=1.0" />
                <title>CodeMaker</title>
                <style>::selection {background: transparent;}</style>
              </head>
              <body style="padding-left: 0; padding-right: 0" ondrop="handleDrop(event)" ondragenter="handleDragEnter(event)" ondragover="handleDragEnter(event)" ondragleave="handleDragLeave(event)" onDragEnd="handleDragLeave(event)">
                <iframe
                  src="${iframeUrl}"
                  frameborder="0"
                  style="width: 100%; height: calc(100vh - 3px)"
                  id="codemaker-webui"
                  sandbox="allow-scripts allow-same-origin allow-forms allow-pointer-lock allow-downloads"
                  allow="cross-origin-isolated; autoplay; local-network-access; clipboard-read; clipboard-write"
                ></iframe>
              </body>
              <script>
                const iframeuri = "${iframeUrl}";
                const iframe = document.getElementById("codemaker-webui");
                const vscode = acquireVsCodeApi();
                window.addEventListener("message", (event) => {
                  // 只接受从指定的域名发送过来的消息
                  if (event.origin === "${origin}") {
                    vscode.postMessage(event.data);
                    console.log("[Event] From ${WEBVIEW_ID}", event.data);
                    ${KEYBOARDS_SHORTCUTS_FIXED_CODE}
                  } else if (
                      event.origin && (event.origin.startsWith('vscode-webview') ${validOrigin
        ? '|| event.origin.includes("' + validOrigin + '")'
        : ''
      })
                  ) {
                    iframe.contentWindow.postMessage(event.data, iframeuri);
                    console.log("[Event] To ${WEBVIEW_ID}", event.data);
                  } else {
                    console.log("[Event] Unknown in ${WEBVIEW_ID}", event);
                  }
                });
              </script>
              <script>
                function handleDrop(e) {
                  e.preventDefault();
                  iframe.contentWindow.postMessage({type: 'ON_WEBVIEW_DROP', data: {
                    files: e.dataTransfer.files,
                    resourceUrlsData: e.dataTransfer.getData("resourceurls"),
                  }}, iframeuri);
                }
                function handleDragEnter(e) {
                  e.preventDefault();
                  iframe.contentWindow.postMessage({type: 'ON_WEBVIEW_DRAG_ENTER'}, iframeuri);
                }
                function handleDragLeave(e) {
                  e.preventDefault();
                  iframe.contentWindow.postMessage({type: 'ON_WEBVIEW_DRAG_LEAVE'}, iframeuri);
                }
              </script>
            </html>`;
  }

  public stopResponse() {
    if (this.requestController) {
      this.requestController.abort();
      this.requestController = null;
    }
    if (this._view) {
      this._view.webview.postMessage({
        type: 'receiveEnd',
      });
    }
  }

  public async sendInitData(isExpired?: boolean, targetWebview?: vscode.Webview) {
    let isLogin = false;
    let accessToken = '';
    const username = this.extensionContext?.globalState.get('username');
    if (isExpired) {
      const renewSuccess = await renewToken(
        this.extensionContext as vscode.ExtensionContext
      );
      if (!renewSuccess) {
        vscode.window
          .showErrorMessage('登录信息失效，请重新登录', '登录')
          .then((selection) => {
            if (selection === '登录') {
              login();
            }
            return;
          });
      }
    }
    isLogin = !!this.extensionContext?.globalState.get('isLogin');
    accessToken = getAccessToken();
    const codeGenerateModel = this.extensionContext?.globalState.get(
      'code_generate_model'
    );
    const codeGenerateModelCode = this.extensionContext?.globalState.get(
      'code_generate_model_code'
    );

    const gatewayName = this.extensionContext?.globalState.get('gateway_name');
    const IDE = 'vscode';
    const newCodeReview = true;
    // TODO: hardcode mhxy code search logic
    const codeSearchUrl =
      this.extensionContext?.globalState.get('codeSearchUrl');
    const isMhxy = codeSearchUrl
      ? (codeSearchUrl as string).includes('test-ai.nie.netease.com')
      : false;
    const chatSubmitKey = getCodeMakerConfig('ChatSubmitKey');
    const codeChatApiKey = getCodeMakerConfig('CodeChatApiKey');
    const CodeChatTerminalTimeout = getCodeMakerConfig('CodeChatTerminalTimeout');
    const codebaseDefaultAuthorizationPath =
      getCodeMakerConfig('CodebaseDefaultAuthorizationPath') || [];
    const codeChatModelsSetting =
      getCodeMakerConfig('CodeChatModels') || {};
    const codeBaseCheckCommands =
      getCodeMakerConfig('CodeBaseCheckCommands') || [];
    const currentFileAutoAttach =
      getCodeMakerConfig('CurrentFileAutoAttach') || false;
    const disableNewApply = getCodeMakerConfig('DisableNewApply') || false;
    const planModeEnabled = getCodeMakerConfig('PlanMode') || false;
    const themeStyle = [
      vscode.ColorThemeKind.Dark,
      vscode.ColorThemeKind.HighContrast
    ].includes(vscode.window.activeColorTheme.kind) ? 'dark' : 'light'

    const initDataMessage = {
      type: 'INIT_DATA',
      data: injectBasicConfig({
        username,
        accessToken,
        codeGenerateModel,
        gatewayName,
        IDE,
        isLogin,
        newCodeReview,
        isMhxy,
        enableAutoExecuteCommand: false,
        codeGenerateModelCode: codeGenerateModelCode,
        submitKey: chatSubmitKey,
        TEAM_REVIEW_API_URL: isTestVersion ? TEAM_REVIEW_API_URL : '',
        CODE_COVERAGE_API_URL: isTestVersion ? CODE_COVERAGE_API_URL : '',
        CODE_SCAN_API_URL: isTestVersion ? CODE_SCAN_API_URL : '',
        codeChatApiKey: codeChatApiKey,
        codeChatTerminalTimeout: CodeChatTerminalTimeout,
        codebaseDefaultAuthorizationPath: codebaseDefaultAuthorizationPath,
        codeChatModelsSetting: codeChatModelsSetting,
        codeBaseCheckCommands: codeBaseCheckCommands,
        currentFileAutoAttach: currentFileAutoAttach,
        disableNewApply: disableNewApply,
        planModeEnabled: planModeEnabled,
        themeStyle,
      }),
    };

    // 如果指定了目标 webview，直接发送给它
    if (targetWebview) {
      targetWebview.postMessage(initDataMessage);
    } else {
      // 否则广播到所有 webview
      this.sendWebviewMessage(initDataMessage, { targetType: 'all' });
    }
  }

  public updatePanelState(context: vscode.ExtensionContext) {
    if (this._panel) {
      const panelState: BaseWebviewState = {
        isOpen: true,
        viewColumn: this._panel.viewColumn as number,
      };

      context.workspaceState.update('webviewPanelState', panelState);
    }
  }

  public openWebviewPanel(viewColumn?: number) {
    // 如果已经打开了 panel ，那么就不能再打开一个新面板
    if (this._panel) return;
    this._panel = vscode.window.createWebviewPanel(
      'webviewPanel',
      'CODEMAKER',
      viewColumn || vscode.ViewColumn.One,
      {
        enableScripts: true,
        // 保留上下文，如果设置为 false 的话，切换 Tab 会导致 Panel 会被销毁
        retainContextWhenHidden: true,
      }
    );
    this.updatePanelState(this.context);
    const origin = WEBVIEW_URL;
    const hash = new Date().getTime();
    const iframeUrl = `${WEBVIEW_URL}?hash=${hash || ''}`;
    const codeServerUrl = (getCodeMakerConfig('CodeServerUrl') as string) || '';
    let validOrigin = '';
    try {
      const urlObj = new URL(codeServerUrl);
      validOrigin = urlObj.origin;
    } catch (err) {
      printLog(`CodeServerUrl 格式不正确，${getErrorMessage(err)}`);
    }
    if (this._panel.webview) {
      this._panel.webview.html = `<!DOCTYPE html>
                                  <html lang="en">
                                    <head>
                                      <meta charset="UTF-8" />
                                      <meta name="viewport" content="width=device-width, initial-scale=1.0" />
                                      <title>CodeMaker</title>
                                      <style>::selection {background: transparent;}</style>
                                    </head>
                                    <body style="padding-left: 0; padding-right: 0" ondrop="handleDrop(event)" ondragenter="handleDragEnter(event)" ondragover="handleDragEnter(event)" ondragleave="handleDragLeave(event)" onDragEnd="handleDragLeave(event)">
                                      <iframe
                                        src="${iframeUrl}"
                                        frameborder="0"
                                        style="width: 100%; height: calc(100vh - 3px)"
                                        id="codemaker-webui-panel"
                                        allow="cross-origin-isolated; autoplay; clipboard-read; clipboard-write"
                                      ></iframe>
                                    </body>
                                    <script>
                                      const iframeuri = "${iframeUrl}";
                                      const iframe = document.getElementById('codemaker-webui-panel');
                                      const vscode = acquireVsCodeApi();
                                      window.addEventListener('message', event => {
                                        if (event.origin === "${origin}") {
                                          vscode.postMessage(event.data);
                                          console.log("[Event] From ${WEBVIEW_ID}", event.data);
                                          ${KEYBOARDS_SHORTCUTS_FIXED_CODE}
                                        } else if (
                                          event.origin && (
                                            event.origin.startsWith('vscode-webview') ${validOrigin
          ? '|| event.origin.includes("' + validOrigin + '")'
          : ''
        })
                                        ) {
                                          iframe.contentWindow.postMessage(event.data, iframeuri);
                                          console.log("[Event] To ${WEBVIEW_ID}", event.data);
                                        } else {
                                          console.log("[Event] Unknown in ${WEBVIEW_ID}", event);
                                        }
                                      });
                                    </script>
                                    <script>
                                      function handleDrop(e) {
                                        e.preventDefault();
                                        iframe.contentWindow.postMessage({type: 'ON_WEBVIEW_DROP', data: {
                                          files: e.dataTransfer.files,
                                          resourceUrlsData: e.dataTransfer.getData("resourceurls"),
                                        }}, iframeuri);
                                      }
                                      function handleDragEnter(e) {
                                        e.preventDefault();
                                        iframe.contentWindow.postMessage({type: 'ON_WEBVIEW_DRAG_ENTER'}, iframeuri);
                                      }
                                      function handleDragLeave(e) {
                                        e.preventDefault();
                                        iframe.contentWindow.postMessage({type: 'ON_WEBVIEW_DRAG_LEAVE'}, iframeuri);
                                      }
                                    </script>
                                  </html>`;

      // 监听来自新 Webview 面板的消息
      this._panel.webview.onDidReceiveMessage(
        async (message) => {
          this.panelInit = true;
          if (this?._panel?.webview) {
            void this.handleMessage(message, this._panel.webview);
          }
        },
        undefined,
        this.context.subscriptions
      );

      // 当 Webview 面板被关闭时进行清理
      this._panel.onDidDispose(
        () => {
          this._panel = null;
          this.context.workspaceState.update('webviewPanelState', null);
        },
        null,
        this.context.subscriptions
      );
      // 当面板位置发生变化的时候，需要更新缓存的位置信息
      this._panel.onDidChangeViewState(
        () => {
          this.updatePanelState(this.context);
        },
        null,
        this.context.subscriptions
      );
    }
  }

  public isInited() {
    return !!this._view;
  }
}

let webviewProvider: CodeStreamWebviewProvider | null = null;

export function initWebviewProvider(context: vscode.ExtensionContext) {
  webviewProvider = new CodeStreamWebviewProvider(context);
  return webviewProvider;
}

export function getWebviewProvider() {
  if (webviewProvider) {
    return webviewProvider;
  }
}

