--- a/src/utils/terminal/TerminalProcess.ts
+++ b/src/utils/terminal/TerminalProcess.ts
@@ -28,6 +28,90 @@ export class TerminalProcess extends EventEmitter<TerminalProcessEvents> {
   private childProcess: ChildProcess | null = null
   private hasShellIntegration: boolean = false

+  // 缓存解析后的 shell 环境变量
+  private static resolvedEnv: NodeJS.ProcessEnv | null = null
+  private static envResolvePromise: Promise<NodeJS.ProcessEnv> | null = null
+
+  /**
+   * 解析用户交互式 shell 的完整环境变量（仅执行一次，结果缓存）。
+   *
+   * Linux 上 nvm/pyenv 等版本管理工具通常配置在 .bashrc 中，
+   * 而 .bashrc 有非交互式 guard（case $- in *i*) ;; *) return;; esac），
+   * 导致 bash -c 无法加载这些工具的 PATH。
+   *
+   * 方案：启动时用 shell -i -c 'env -0' 解析一次完整的交互式环境，
+   * 之后所有命令用非交互式 shell + 已解析的环境来执行，
+   * 避免每次都用 -i 带来的副作用（别名展开、stderr 噪音、启动延迟等）。
+   */
+  static async resolveShellEnv(): Promise<NodeJS.ProcessEnv> {
+    if (TerminalProcess.resolvedEnv) {
+      return TerminalProcess.resolvedEnv
+    }
+
+    if (TerminalProcess.envResolvePromise) {
+      return TerminalProcess.envResolvePromise
+    }
+
+    TerminalProcess.envResolvePromise = new Promise<NodeJS.ProcessEnv>((resolve) => {
+      if (process.platform === 'win32') {
+        TerminalProcess.resolvedEnv = { ...process.env }
+        resolve(TerminalProcess.resolvedEnv)
+        return
+      }
+
+      const shell = process.env.SHELL || '/bin/bash'
+      // 用登录+交互式 shell 执行 env -0，获取 NUL 分隔的完整环境变量。
+      // -l（登录）：加载 /etc/profile → ~/.profile，获取 ~/.local/bin 等路径配置。
+      // -i（交互）：使 .bashrc 的非交互式 guard 通过，加载 nvm/pyenv 等工具。
+      // 两者结合才能获取用户完整的 PATH 环境。
+      const child = spawn(shell, ['-l', '-i', '-c', 'env -0'], {
+        stdio: ['pipe', 'pipe', 'pipe'],
+        env: process.env,
+      })
+
+      let stdout = ''
+      child.stdout.on('data', (data: Buffer) => { stdout += data.toString() })
+      // 忽略 stderr（bash 的 "no job control" 等警告）
+      child.stderr.on('data', () => {})
+
+      // 设置超时，防止交互式 shell 卡住
