import { EventEmitter } from "events"
import { getUTF8String, stripAnsi } from "./ansiUtils"
import * as vscode from "vscode"
import { ChildProcess, exec, spawn } from 'child_process'
import getErrorMessage from "../getErrorMessage"

export interface TerminalProcessEvents {
  line: [line: string]
  continue: []
  completed: []
  error: [error: Error]
  no_shell_integration: []
  exit: [code: number]
}

// how long to wait after a process outputs anything before we consider it "cool" again
const PROCESS_HOT_TIMEOUT_NORMAL = 2_000
const PROCESS_HOT_TIMEOUT_COMPILING = 20_000

export class TerminalProcess extends EventEmitter<TerminalProcessEvents> {
  waitForShellIntegration: boolean = true
  private isListening: boolean = true
  private buffer: string = ""
  private fullOutput: string = ""
  private lastRetrievedIndex: number = 0
  isHot: boolean = false
  private hotTimer: NodeJS.Timeout | null = null
  private childProcess: ChildProcess | null = null
  private hasShellIntegration: boolean = false

  // 缓存解析后的 shell 环境变量
  private static resolvedEnv: NodeJS.ProcessEnv | null = null
  private static envResolvePromise: Promise<NodeJS.ProcessEnv> | null = null

  /**
   * 解析用户交互式 shell 的完整环境变量（仅执行一次，结果缓存）。
   *
   * Linux 上 nvm/pyenv 等版本管理工具通常配置在 .bashrc 中，
   * 而 .bashrc 有非交互式 guard（case $- in *i*) ;; *) return;; esac），
   * 导致 bash -c 无法加载这些工具的 PATH。
   *
   * 方案：启动时用 shell -i -c 'env -0' 解析一次完整的交互式环境，
   * 之后所有命令用非交互式 shell + 已解析的环境来执行，
   * 避免每次都用 -i 带来的副作用（别名展开、stderr 噪音、启动延迟等）。
   */
  static async resolveShellEnv(): Promise<NodeJS.ProcessEnv> {
    if (TerminalProcess.resolvedEnv) {
      return TerminalProcess.resolvedEnv
    }

    if (TerminalProcess.envResolvePromise) {
      return TerminalProcess.envResolvePromise
    }

    TerminalProcess.envResolvePromise = new Promise<NodeJS.ProcessEnv>((resolve) => {
      if (process.platform === 'win32') {
        TerminalProcess.resolvedEnv = { ...process.env }
        resolve(TerminalProcess.resolvedEnv)
        return
      }

      const shell = process.env.SHELL || '/bin/bash'
      // 用登录+交互式 shell 执行 env -0，获取 NUL 分隔的完整环境变量。
      // -l（登录）：加载 /etc/profile → ~/.profile，获取 ~/.local/bin 等路径配置。
      // -i（交互）：使 .bashrc 的非交互式 guard 通过，加载 nvm/pyenv 等工具。
      // 两者结合才能获取用户完整的 PATH 环境。
      const child = spawn(shell, ['-l', '-i', '-c', 'env -0'], {
        stdio: ['pipe', 'pipe', 'pipe'],
        env: process.env,
      })

      let stdout = ''
      child.stdout.on('data', (data: Buffer) => { stdout += data.toString() })
      // 忽略 stderr（bash 的 "no job control" 等警告）
      child.stderr.on('data', () => {})

      // 设置超时，防止交互式 shell 卡住
      const timeout = setTimeout(() => {
        child.kill('SIGKILL')
      }, 10000)

      child.on('close', () => {
        clearTimeout(timeout)
        const env: NodeJS.ProcessEnv = { ...process.env }

        if (stdout) {
          // 解析 NUL 分隔的环境变量
          const entries = stdout.split('\0')
          for (const entry of entries) {
            const eqIndex = entry.indexOf('=')
            if (eqIndex > 0) {
              env[entry.substring(0, eqIndex)] = entry.substring(eqIndex + 1)
            }
          }
        }

        TerminalProcess.resolvedEnv = env
        resolve(env)
      })

      child.on('error', () => {
        clearTimeout(timeout)
        // 解析失败时回退到 process.env
        TerminalProcess.resolvedEnv = { ...process.env }
        resolve(TerminalProcess.resolvedEnv)
      })

      // 关闭 stdin，防止交互式 shell 等待输入
      child.stdin.end()
    })

    return TerminalProcess.envResolvePromise
  }


  async run(terminal: vscode.Terminal, command: string, cwd: string) {
    // if (terminal.shellIntegration?.executeCommand) {
    // 	this.hasShellIntegration = true
    // 	await this.runWithShellIntegration(terminal, command)
    // 	this.emit("completed")
    // 	this.emit("continue")
    // } else {
    this.hasShellIntegration = false
    this.emit("no_shell_integration")
    await this.runWithoutShellIntegration(command, cwd)
    this.emit("completed")
    this.emit("continue")
    // }
  }


  private async runWithShellIntegration(terminal: vscode.Terminal, command: string) {
    if (terminal.shellIntegration && terminal.shellIntegration.executeCommand) {
      const execution = terminal.shellIntegration.executeCommand(command)
      const stream = execution.read()
      // todo: need to handle errors
      let isFirstChunk = true
      let didOutputNonCommand = false
      let didEmitEmptyLine = false
      for await (let data of stream) {
        if (isFirstChunk) {
          const outputBetweenSequences = this.removeLastLineArtifacts(
            data.match(/\]633;C([\s\S]*?)\]633;D/)?.[1] || "",
          ).trim()

          // Once we've retrieved any potential output between sequences, we can remove everything up to end of the last sequence
          // https://code.visualstudio.com/docs/terminal/shell-integration#_vs-code-custom-sequences-osc-633-st
          const vscodeSequenceRegex = /\x1b\]633;.[^\x07]*\x07/g
          const lastMatch = [...data.matchAll(vscodeSequenceRegex)].pop()
          if (lastMatch && lastMatch.index !== undefined) {
            data = data.slice(lastMatch.index + lastMatch[0].length)
          }
          // Place output back after removing vscode sequences
          if (outputBetweenSequences) {
            data = outputBetweenSequences + "\n" + data
          }
          // remove ansi
          data = stripAnsi(data)
          // Split data by newlines
          const lines = data ? data.split("\n") : []
          // Remove non-human readable characters from the first line
          if (lines.length > 0) {
            lines[0] = lines[0].replace(/[^\x20-\x7E]/g, "")
          }
          // Check for duplicated first character that might be a terminal artifact
          // But skip this check for known syntax characters like {, [, ", etc.
          if (
            lines.length > 0 &&
            lines[0].length >= 2 &&
            lines[0][0] === lines[0][1] &&
            !["[", "{", '"', "'", "<", "("].includes(lines[0][0])
          ) {
            lines[0] = lines[0].slice(1)
          }
          // Only remove specific terminal artifacts from line beginnings while preserving JSON syntax
          if (lines.length > 0) {
            // This regex only removes common terminal artifacts (%, $, >, #) and invisible control chars
            // but preserves important syntax chars like {, [, ", etc.
            lines[0] = lines[0].replace(/^[\x00-\x1F%$>#\s]*/, "")
          }
          if (lines.length > 1) {
            lines[1] = lines[1].replace(/^[\x00-\x1F%$>#\s]*/, "")
          }
          // Join lines back
          data = lines.join("\n")
          isFirstChunk = false
        } else {
          data = stripAnsi(data)
        }
        // Ctrl+C detection: if user presses Ctrl+C, treat as command terminated
        if (data.includes("^C") || data.includes("\u0003")) {
          if (this.hotTimer) {
            clearTimeout(this.hotTimer)
          }
          this.isHot = false
          break
        }

        // first few chunks could be the command being echoed back, so we must ignore
        // note this means that 'echo' commands won't work
        if (!didOutputNonCommand) {
          const lines = data.split("\n")
          for (let i = 0; i < lines.length; i++) {
            if (command.includes(lines[i].trim())) {
              lines.splice(i, 1)
              i-- // Adjust index after removal
            } else {
              didOutputNonCommand = true
              break
            }
          }
          data = lines.join("\n")
        }

        // 2. Set isHot depending on the command
        // Set to hot to stall API requests until terminal is cool again
        this.updateHotState(data)

        // For non-immediately returning commands we want to show loading spinner right away but this wouldn't happen until it emits a line break, so as soon as we get any output we emit "" to let webview know to show spinner
        if (!didEmitEmptyLine && !this.fullOutput && data) {
          this.emit("line", "") // empty line to indicate start of command output stream
          didEmitEmptyLine = true
        }

        this.fullOutput += data
        if (this.isListening) {
          this.emitIfEol(data)
          this.lastRetrievedIndex = this.fullOutput.length - this.buffer.length
        }
      }

      this.emitRemainingBufferIfListening()
      this.clearHotState()
    }
  }

  private getDefaultShell(): string {
    if (process.platform === "win32") {
      return process.env.COMSPEC || "cmd.exe"
    } else {
      return process.env.SHELL || "/bin/bash"
    }
  }

  private static isResolveShellEnvEnabled(): boolean {
    const config = vscode.workspace.getConfiguration('CodeMaker')
    return config.get<boolean>('ResolveShellEnv', true)
  }

  private getShellArgs(shell: string, command: string): string[] {
    if (process.platform === "win32") {
      if (shell.toLowerCase().includes("powershell") || shell.toLowerCase().includes("pwsh")) {
        return ["-Command", command]
      } else {
        return ["/c", command]
      }
    } else {
      if (TerminalProcess.isResolveShellEnvEnabled()) {
        // 非交互式执行命令，依赖 resolveShellEnv() 提供的完整环境变量。
        return ["-c", command]
      } else {
        // 回退到原始行为：登录 shell 加载 profile 文件
        // Use -l for login shell, -c for command
        return ["-l", "-c", command]
      }
    }
  }

  private async runWithoutShellIntegration(command: string, cwd: string) {
    return new Promise(async (resolve) => {
      const shell = this.getDefaultShell()
      // 根据设置决定使用预解析的环境还是原始 process.env
      const baseEnv = TerminalProcess.isResolveShellEnvEnabled()
        ? await TerminalProcess.resolveShellEnv()
        : process.env
      const shellOptions: {
        env: NodeJS.ProcessEnv
        shell?: boolean
        stdio: "pipe",
        cwd: string
      } = {
        stdio: "pipe",
        env: {
          ...baseEnv,
          // 强制使用 UTF-8 编码，解决 Windows GBK 编码无法输出 emoji/中文等字符的问题
          // Python
          PYTHONIOENCODING: 'utf-8',
          PYTHONUTF8: '1',
          // Node.js
          NODE_OPTIONS: process.env.NODE_OPTIONS
            ? `${process.env.NODE_OPTIONS} --no-warnings`
            : '--no-warnings',
          // 通用 (Git, Ruby, Perl 等)
          LANG: 'C.UTF-8',
          LC_ALL: 'C.UTF-8',
          // Windows cmd.exe 代码页
          CHCP: '65001',
        },
        cwd: cwd || vscode.workspace.workspaceFolders?.[0]?.uri?.fsPath || process.cwd(),
      }
      let childProcess = null
      if (shell.toLowerCase().includes("cmd")) {
        shellOptions.shell = true
        childProcess = spawn(
          command,
          [],
          // this.getShellArgs(shell, command),
          shellOptions
        )
      } else {
        childProcess = spawn(
          shell,
          this.getShellArgs(shell, command),
          shellOptions,
        )
      }
      this.childProcess = childProcess
      let didEmitEmptyLine = false
      this.isHot = true

      childProcess.stdout.on("data", (data) => {
        let output = getUTF8String(data);
        // 发送空行表示命令开始执行
        if (!didEmitEmptyLine && !this.fullOutput && output) {
          this.emit("line", "")
          didEmitEmptyLine = true
        }
        this.fullOutput += output
        if (this.isListening) {
          this.buffer += data.toString()
          this.emit("line", output)
          this.lastRetrievedIndex = this.fullOutput.length - this.buffer.length
        }
      })

      childProcess.stderr.on("data", (data) => {
        let output = getUTF8String(data);
        this.fullOutput += output
        if (this.isListening) {
          this.buffer += data.toString()
          this.emit("line", output)
          this.lastRetrievedIndex = this.fullOutput.length - this.buffer.length
        }
      })

      childProcess.on("error", (error) => {
        this.emit("error", getErrorMessage(error))
      })

      childProcess.on("exit", (code) => {
        this.emit('exit', code || 0)
        this.isHot = false
        this.emitRemainingBufferIfListening()
        this.clearHotState()
        resolve(code)
      })
    })
  }

  private detectCompilationStatus(data: string): boolean {
    // these markers indicate the command is some kind of local dev server recompiling the app
    const compilingMarkers = ["compiling", "building", "bundling", "transpiling", "generating", "starting"]
    const markerNullifiers = [
      "compiled",
      "success",
      "finish",
      "complete",
      "succeed",
      "done",
      "end",
      "stop",
      "exit",
      "terminate",
      "error",
      "fail",
    ]

    return (
      compilingMarkers.some((marker) => data.toLowerCase().includes(marker.toLowerCase())) &&
      !markerNullifiers.some((nullifier) => data.toLowerCase().includes(nullifier.toLowerCase()))
    )
  }

  private updateHotState(data: string): void {
    this.clearHotState()
    this.isHot = true
    const isCompiling = typeof data === 'string' ? this.detectCompilationStatus(data) : true
    const timeout = isCompiling ? PROCESS_HOT_TIMEOUT_COMPILING : PROCESS_HOT_TIMEOUT_NORMAL
    this.hotTimer = setTimeout(() => {
      this.isHot = false
    }, timeout)
  }

  private clearHotState(): void {
    if (this.hotTimer) {
      clearTimeout(this.hotTimer)
    }
    this.isHot = false
  }

  // Inspired by https://github.com/sindresorhus/execa/blob/main/lib/transform/split.js
  private emitIfEol(chunk: string) {
    this.buffer += chunk
    let lineEndIndex: number
    while ((lineEndIndex = this.buffer.indexOf("\n")) !== -1) {
      let line = this.buffer.slice(0, lineEndIndex).trimEnd() // removes trailing \r
      try {
        const strBuffer = Buffer.from(line, 'binary');
        this.emit("line", strBuffer.toString('utf8'))
      } catch (e) {
        this.emit("line", line)
      }
      this.buffer = this.buffer.slice(lineEndIndex + 1)
    }
  }

  private emitRemainingBufferIfListening() {
    if (this.buffer && this.isListening) {
      const remainingBuffer = this.removeLastLineArtifacts(this.buffer)
      if (remainingBuffer && this.hasShellIntegration) {
        this.emit("line", remainingBuffer)
      }
      this.buffer = ""
      this.lastRetrievedIndex = this.fullOutput.length
    }
  }

  continue() {
    this.emitRemainingBufferIfListening()
    this.emit("continue")
  }

  stop() {
    this.isListening = false
    this.removeAllListeners("line")
    if (this.childProcess) {
      this.childProcess.kill()
    }
  }

  getUnretrievedOutput(): string {
    const unretrieved = this.fullOutput.slice(this.lastRetrievedIndex)
    this.lastRetrievedIndex = this.fullOutput.length
    return this.removeLastLineArtifacts(unretrieved)
  }

  // some processing to remove artifacts like '%' at the end of the buffer (it seems that since vsode uses % at the beginning of newlines in terminal, it makes its way into the stream)
  // This modification will remove '%', '$', '#', or '>' followed by optional whitespace
  removeLastLineArtifacts(output: string) {
    const lines = output.trimEnd().split("\n")
    if (lines.length > 0) {
      const lastLine = lines[lines.length - 1]
      // Remove prompt characters and trailing whitespace from the last line
      lines[lines.length - 1] = lastLine.replace(/[%$#>]\s*$/, "")
    }
    return lines.join("\n").trimEnd()
  }
}

export type TerminalProcessResultPromise = TerminalProcess & Promise<void>

// Similar to execa's ResultPromise, this lets us create a mixin of both a TerminalProcess and a Promise: https://github.com/sindresorhus/execa/blob/main/lib/methods/promise.js
export function mergePromise(process: TerminalProcess, promise: Promise<void>): TerminalProcessResultPromise {
  const nativePromisePrototype = (async () => { })().constructor.prototype
  const descriptors = ["then", "catch", "finally"].map(
    (property) => [property, Reflect.getOwnPropertyDescriptor(nativePromisePrototype, property)] as const,
  )
  for (const [property, descriptor] of descriptors) {
    if (descriptor) {
      const value = descriptor.value.bind(promise)
      Reflect.defineProperty(process, property, { ...descriptor, value })
    }
  }
  return process as TerminalProcessResultPromise
}
